import base64
import pickle
from google.cloud import pubsub_v1

def process_batch_jobs(event, context):
    """Cloud Function that processes batch jobs from the task queue."""
    # Decode the Pub/Sub message data and deserialize it using pickle
    message = base64.b64decode(event['data']).decode('utf-8')
    job_data = pickle.loads(message)
    
    # Process the batch job using the deserialized data
    process_batch_job(job_data)